+func symbolBlock(content string, symbol SymbolRecord) string {
+	lines := strings.Split(content, "\n")
+	start := symbol.StartLine - 1
+	if start < 0 {
+		start = 0
+	}
+	end := symbol.EndLine
+	if end > len(lines) {
+		end = len(lines)
+	}
+	if end <= start {
+		return ""
+	}
+	return strings.Join(lines[start:end], "\n")
+}
+
+func completenessLevel(failures, files int) string {
+	switch {
