	"strings"

	"github.com/suhaanthayyil/entire-sem/internal/gitutil"
)

const (
	SchemaVersion         = "1.0"
	ProviderName          = "entire-sem"
	StableSymbolIDVersion = "1"
)

var relationTypes = []string{
	"DEFINES",
	"CONTAINS",
	"IMPORTS",
	"CALLS",
	"IMPLEMENTS",
	"EXTENDS",
	"OVERRIDES",
	"ACCESSES",
	"HANDLES_ROUTE",
	"HANDLES_TOOL",
}

type Warning struct {
	Code   string `json:"code"`
	Severity string `json:"severity"`
	Path   string `json:"path,omitempty"`
	Effect string `json:"effect"`
	Detail string `json:"detail,omitempty"`
}

type SnapshotHeader struct {
	SchemaVersion   string    `json:"schema_version"`
	Provider        string    `json:"provider"`
	ProviderVersion string    `json:"provider_version"`
	RepoRoot        string    `json:"repo_root"`
	RepoKey         string    `json:"repo_key"`
	Commit          string    `json:"commit"`
	Tree            string    `json:"tree"`
	Languages       []string  `json:"languages"`
	Capabilities    []string  `json:"capabilities"`
	Warnings        []Warning `json:"warnings"`
	PartialFailures []Warning `json:"partial_failures"`
	Stats           Stats     `json:"stats"`
}

type Stats struct {
	FilesScanned    int    `json:"files_scanned"`
	FilesParsed     int    `json:"files_parsed"`
	FilesFailed     int    `json:"files_failed"`
	SymbolsEmitted  int    `json:"symbols_emitted"`
	RelationsEmitted int   `json:"relations_emitted"`
	Completeness    string `json:"completeness"`
}

type FileRecord struct {
	RecordType string `json:"record_type"`
	Path       string `json:"path"`
	Blob       string `json:"blob"`
	Language   string `json:"language"`
}

type SymbolRecord struct {
	RecordType        string `json:"record_type"`
	ID                string `json:"id"`
	StableIDVersion   string `json:"stable_id_version"`
	Kind              string `json:"kind"`
	Name              string `json:"name"`
	QualifiedName     string `json:"qualified_name"`
	FilePath          string `json:"file_path"`
	StartLine         int    `json:"start_line"`
	EndLine           int    `json:"end_line"`
	Signature         string `json:"signature"`
	BodyHash          string `json:"body_hash"`
	Language          string `json:"language"`
	ContainerID       string `json:"container_id,omitempty"`
}

type RelationRecord struct {
	RecordType   string   `json:"record_type"`
	FromID       string   `json:"from_id"`
	ToID         string   `json:"to_id"`
	Type         string   `json:"type"`
	Confidence   float64  `json:"confidence"`
	Reason       string   `json:"reason"`
	WarningCodes []string `json:"warning_codes,omitempty"`
}

type Snapshot struct {
	Header    SnapshotHeader
	Files     []FileRecord
	Symbols   []SymbolRecord
	Relations []RelationRecord
}

type Capabilities struct {
	SchemaVersion                     string   `json:"schema_version"`
	Provider                          string   `json:"provider"`
	SupportedFileExtensions           []string `json:"supported_file_extensions"`
	SupportedLanguages                []string `json:"supported_languages"`
	ParserVersions                    []string `json:"parser_versions"`
	SupportedRelationTypes            []string `json:"supported_relation_types"`
	UnsupportedButDetectedLanguageHints []string `json:"unsupported_but_detected_language_hints"`
	OptionalLocalOnlyFeaturesAvailable []string `json:"optional_local_only_features_available"`
	FeaturesRequiringNetworkAccess    []string `json:"features_requiring_network_access"`
}

func BuildSnapshot(ctx context.Context, repo, providerVersion string) (Snapshot, error) {
	absRepo, err := filepath.Abs(repo)
	if err != nil {
		return Snapshot{}, err
	}
	repoKey := repoKey(ctx, absRepo)
	snapshot := Snapshot{
		Header: SnapshotHeader{
			SchemaVersion:   SchemaVersion,
			Provider:        ProviderName,
			ProviderVersion: providerVersion,
			RepoRoot:        absRepo,
			RepoKey:         repoKey,
			Capabilities:    providerCapabilities(),
		},
	}
	if commit, err := gitutil.RevParse(ctx, absRepo, "HEAD"); err == nil {
		snapshot.Header.Commit = commit
	}
	if tree, err := gitutil.RevParse(ctx, absRepo, "HEAD^{tree}"); err == nil {
		snapshot.Header.Tree = tree
	}

	files, err := providerFiles(absRepo)
	if err != nil {
		return Snapshot{}, err
	}
	parser := TreeSitterParser{}
	byShortName := map[string][]SymbolRecord{}
	byQualifiedName := map[string]SymbolRecord{}
	languages := map[string]struct{}{}

	for _, path := range files {
		snapshot.Header.Stats.FilesScanned++
		content, err := os.ReadFile(filepath.Join(absRepo, filepath.FromSlash(path)))
		if err != nil {
			snapshot.Header.PartialFailures = append(snapshot.Header.PartialFailures, Warning{
				Code: "E_READ_FILE", Severity: "error", Path: path,
				Effect: "file omitted from semantic snapshot", Detail: err.Error(),
			})
			snapshot.Header.Stats.FilesFailed++
			continue
		}
		entities, language := parser.Parse(path, string(content))
		if language == "" {
			continue
		}
		languages[language] = struct{}{}
		snapshot.Header.Stats.FilesParsed++
		fileID := fileID(repoKey, path)
		snapshot.Files = append(snapshot.Files, FileRecord{
			RecordType: "file",
			Path:       path,
			Blob:       contentHash(content),
			Language:   language,
		})
		for _, entity := range entities {
			symbol := symbolRecord(repoKey, path, language, entity)
			snapshot.Symbols = append(snapshot.Symbols, symbol)
			byShortName[shortEntityName(symbol.QualifiedName)] = append(byShortName[shortEntityName(symbol.QualifiedName)], symbol)
			byQualifiedName[symbol.QualifiedName] = symbol
			snapshot.Relations = append(snapshot.Relations, RelationRecord{
				RecordType: "relation", FromID: fileID, ToID: symbol.ID, Type: "DEFINES",
				Confidence: 1, Reason: "symbol parsed from file",
			})
			if symbol.ContainerID != "" {
				snapshot.Relations = append(snapshot.Relations, RelationRecord{
					RecordType: "relation", FromID: symbol.ContainerID, ToID: symbol.ID, Type: "CONTAINS",
					Confidence: 1, Reason: "symbol has lexical container",
				})
			}
		}
	}

	for _, path := range files {
		content, err := os.ReadFile(filepath.Join(absRepo, filepath.FromSlash(path)))
		if err != nil || !Supported(path) {
			continue
		}
		entities, _ := parser.Parse(path, string(content))
		lines := strings.Split(string(content), "\n")
		snapshot.Relations = append(snapshot.Relations, importRelations(repoKey, path, string(content))...)
		for _, entity := range entities {
			from := symbolID(repoKey, languageName(path), path, entity.Kind, entity.Name)
			block := entityBlock(lines, entity)
			snapshot.Relations = append(snapshot.Relations, callRelations(from, block, byShortName)...)
			snapshot.Relations = append(snapshot.Relations, routeToolRelations(repoKey, from, block)...)
		}
	}

	sortRecords(&snapshot)
	for language := range languages {
		snapshot.Header.Languages = append(snapshot.Header.Languages, language)
	}
	sort.Strings(snapshot.Header.Languages)
	snapshot.Header.Stats.SymbolsEmitted = len(snapshot.Symbols)
	snapshot.Header.Stats.RelationsEmitted = len(snapshot.Relations)
	snapshot.Header.Stats.Completeness = completeness(snapshot.Header.Stats.FilesFailed)
	return snapshot, nil
}

func WriteSnapshotNDJSON(out io.Writer, snapshot Snapshot, records string) error {
	enc := json.NewEncoder(out)
	if records == "snapshot" {
		if err := enc.Encode(snapshot.Header); err != nil {
			return err
		}
	}
	if records == "snapshot" || records == "files" {
		for _, record := range snapshot.Files {
			if err := enc.Encode(record); err != nil {
				return err
			}
		}
	}
	if records == "snapshot" || records == "symbols" {
		for _, record := range snapshot.Symbols {
			if err := enc.Encode(record); err != nil {
				return err
			}
		}
	}
	if records == "snapshot" || records == "edges" {
		for _, record := range snapshot.Relations {
			if err := enc.Encode(record); err != nil {
				return err
			}
		}
	}
	return nil
}

func ProviderCapabilities() Capabilities {
	var extensions []string
	langs := map[string]struct{}{}
	for ext, spec := range treeSitterLanguages {
		extensions = append(extensions, ext)
		langs[spec.language] = struct{}{}
	}
	var languages []string
	for language := range langs {
		languages = append(languages, language)
	}
	sort.Strings(extensions)
	sort.Strings(languages)
	return Capabilities{
		SchemaVersion: SchemaVersion,
		Provider: ProviderName,
		SupportedFileExtensions: extensions,
		SupportedLanguages: languages,
		ParserVersions: []string{"github.com/smacker/go-tree-sitter"},
		SupportedRelationTypes: append([]string(nil), relationTypes...),
		OptionalLocalOnlyFeaturesAvailable: []string{"tree-sitter", "semantic-diff", "stable-symbol-id-v1"},
		FeaturesRequiringNetworkAccess: []string{},
	}
}

func providerFiles(repo string) ([]string, error) {
	var files []string
	err := filepath.WalkDir(repo, func(path string, entry fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if entry.IsDir() {
			switch entry.Name() {
			case ".git", "node_modules", "vendor":
				return filepath.SkipDir
			}
			return nil
		}
		rel, err := filepath.Rel(repo, path)
		if err != nil {
			return err
		}
		rel = filepath.ToSlash(rel)
		if Supported(rel) {
			files = append(files, rel)
		}
		return nil
	})
	sort.Strings(files)
	return files, err
}

func symbolRecord(repoKey, path, language string, entity Entity) SymbolRecord {
	id := symbolID(repoKey, language, path, entity.Kind, entity.Name)
	return SymbolRecord{
		RecordType: "symbol", ID: id, StableIDVersion: StableSymbolIDVersion,
		Kind: entity.Kind, Name: shortEntityName(entity.Name), QualifiedName: entity.Name,
		FilePath: path, StartLine: entity.StartLine, EndLine: entity.EndLine,
		Signature: entity.Signature, BodyHash: entity.BodyHash, Language: language,
		ContainerID: containerID(repoKey, language, path, entity.Name),
	}
}

func importRelations(repoKey, path, content string) []RelationRecord {
	var out []RelationRecord
	scanner := bufio.NewScanner(strings.NewReader(content))
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		var target string
		switch {
		case strings.HasPrefix(line, "import "):
			target = importTarget(line)
		case strings.HasPrefix(line, "from "):
			target = importTarget(line)
		case strings.HasPrefix(line, "use "):
			target = strings.TrimSuffix(strings.TrimPrefix(line, "use "), ";")
		}
		if target == "" {
			continue
		}
		out = append(out, RelationRecord{
			RecordType: "relation", FromID: fileID(repoKey, path), ToID: externalID(target),
			Type: "IMPORTS", Confidence: 0.85, Reason: "import-like declaration parsed from source text",
		})
	}
	return out
}

func importTarget(line string) string {
	line = strings.TrimSpace(strings.TrimSuffix(line, ";"))
	if strings.HasPrefix(line, "import ") {
		rest := strings.TrimSpace(strings.TrimPrefix(line, "import "))
		if strings.HasPrefix(rest, "(") {
			return ""
		}
		if strings.Contains(rest, " from ") {
			parts := strings.Split(rest, " from ")
			return strings.Trim(parts[len(parts)-1], `"'`)
		}
		fields := strings.Fields(rest)
		if len(fields) == 0 {
			return ""
		}
		return strings.Trim(fields[len(fields)-1], `"'`)
	}
	if strings.HasPrefix(line, "from ") {
		fields := strings.Fields(line)
		if len(fields) >= 2 {
			return fields[1]
		}
	}
	return ""
}

var callPattern = regexp.MustCompile(`\b([A-Za-z_][A-Za-z0-9_]*)\s*\(`)

func callRelations(from, block string, symbols map[string][]SymbolRecord) []RelationRecord {
	seen := map[string]struct{}{}
	var out []RelationRecord
	for _, match := range callPattern.FindAllStringSubmatch(block, -1) {
		name := match[1]
		for _, target := range symbols[name] {
			if target.ID == from {
				continue
			}
			key := from + ">" + target.ID
			if _, ok := seen[key]; ok {
				continue
			}
			seen[key] = struct{}{}
			out = append(out, RelationRecord{
				RecordType: "relation", FromID: from, ToID: target.ID, Type: "CALLS",
				Confidence: 0.65, Reason: "callee name appears in executable block",
			})
		}
	}
	return out
}

func routeToolRelations(repoKey, from, block string) []RelationRecord {
	var out []RelationRecord
	lower := strings.ToLower(block)
	if strings.Contains(lower, "route") || strings.Contains(lower, "http.") || strings.Contains(lower, "@app.") {
		out = append(out, RelationRecord{
			RecordType: "relation", FromID: from, ToID: externalID(repoKey+":route"),
			Type: "HANDLES_ROUTE", Confidence: 0.55, Reason: "route-like marker appears near handler",
		})
	}
	if strings.Contains(lower, "tool") || strings.Contains(lower, "functioncall") {
		out = append(out, RelationRecord{
			RecordType: "relation", FromID: from, ToID: externalID(repoKey+":tool"),
			Type: "HANDLES_TOOL", Confidence: 0.55, Reason: "tool-like marker appears near handler",
		})
	}
	return out
}

func repoKey(ctx context.Context, repo string) string {
	if remote, ok := gitutil.RemoteURL(ctx, repo); ok && remote != "" {
		return normalizeRemote(remote)
	}
	return filepath.Base(repo)
}

func normalizeRemote(remote string) string {
	remote = strings.TrimSuffix(remote, ".git")
	remote = strings.TrimPrefix(remote, "git@github.com:")
	remote = strings.TrimPrefix(remote, "https://github.com/")
	if !strings.HasPrefix(remote, "gh/") && strings.Count(remote, "/") == 1 {
		return "gh/" + remote
	}
	return remote
}

func fileID(repoKey, path string) string {
	return repoKey + ":file:" + path
}

func externalID(value string) string {
	return "external:" + value
}

func symbolID(repoKey, language, path, kind, qualifiedName string) string {
	return fmt.Sprintf("%s:%s:%s:%s:%s", repoKey, language, path, kind, qualifiedName)
}

func containerID(repoKey, language, path, qualifiedName string) string {
	index := strings.LastIndex(qualifiedName, ".")
	if index < 0 {
		return ""
	}
	container := qualifiedName[:index]
	return symbolID(repoKey, language, path, "class", container)
}

func languageName(path string) string {
	spec, ok := languageForPath(path)
	if !ok {
		return ""
	}
	return spec.language
}

func contentHash(content []byte) string {
	sum := sha256.Sum256(content)
	return hex.EncodeToString(sum[:])
}

func providerCapabilities() []string {
	return []string{"tree-sitter", "stable-symbol-id-v1", "ndjson-snapshot", "local-only-phase-1"}
}

func completeness(failures int) string {
	if failures == 0 {
		return "ok"
	}
	return "degraded"
}

func sortRecords(snapshot *Snapshot) {
	sort.Slice(snapshot.Files, func(i, j int) bool { return snapshot.Files[i].Path < snapshot.Files[j].Path })
	sort.Slice(snapshot.Symbols, func(i, j int) bool { return snapshot.Symbols[i].ID < snapshot.Symbols[j].ID })
	sort.Slice(snapshot.Relations, func(i, j int) bool {
		left := snapshot.Relations[i]
		right := snapshot.Relations[j]
		if left.FromID != right.FromID {
			return left.FromID < right.FromID
		}
		if left.ToID != right.ToID {
			return left.ToID < right.ToID
		}
		return left.Type < right.Type
	})
}

